/* P-Code VM Debugger panel styles */

.debugger {
    display: flex;
    flex-direction: column;
    flex: 1;
    overflow: hidden;
    min-height: 0;
}

/* Control bar */
.control-bar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 16px;
    border-bottom: 1px solid var(--surface1);
    background: var(--mantle);
    flex-shrink: 0;
}

.btn {
    font-family: var(--mono);
    font-size: 13px;
    padding: 4px 12px;
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
    background: var(--surface0);
    color: var(--text);
    transition: background 0.15s;
}

.btn:hover:not(:disabled) {
    background: var(--surface1);
}

.btn:disabled {
    opacity: 0.4;
    cursor: default;
}

.btn-reset {
    color: var(--red);
    border-color: var(--red);
}

.btn-step {
    color: var(--blue);
    border-color: var(--blue);
}

.btn-step-host {
    color: var(--overlay2);
    border-color: var(--overlay2);
}

.btn-run {
    color: var(--green);
    border-color: var(--green);
}

.btn-toggle {
    color: var(--overlay1);
    border-color: var(--overlay1);
    font-size: 11px;
    padding: 3px 8px;
}

.btn-toggle.active {
    color: var(--peach);
    border-color: var(--peach);
    background: var(--surface1);
}

.status {
    font-size: 13px;
    font-weight: 600;
    margin-left: 8px;
    color: var(--yellow);
}

.pc-display {
    font-size: 13px;
    color: var(--blue);
    margin-left: auto;
}

.host-pc {
    color: var(--overlay2);
    margin-left: 12px;
}

.instr-count {
    font-size: 12px;
    color: var(--overlay1);
    margin-left: 12px;
    font-variant-numeric: tabular-nums;
}

/* Memory region map bar */
.memory-map {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 4px 16px;
    border-bottom: 1px solid var(--surface1);
    flex-shrink: 0;
}

.memory-map-label {
    font-size: 11px;
    color: var(--overlay1);
    flex-shrink: 0;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.region-bar {
    display: flex;
    height: 16px;
    border-radius: 3px;
    overflow: hidden;
    font-size: 10px;
    flex: 1;
}

.region-bar .region {
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--crust);
    font-weight: 700;
    min-width: 2px;
    transition: width 0.3s;
}

.region-bar .region-code { background: var(--blue); }
.region-bar .region-estack { background: var(--green); }
.region-bar .region-cstack { background: var(--peach); }
.region-bar .region-globals { background: var(--mauve); }
.region-bar .region-heap { background: var(--yellow); }

/* Main panels — flexible columns */
.panels {
    display: flex;
    flex: 1;
    overflow: hidden;
    min-height: 0;
}

.panel {
    padding: 8px 12px;
    overflow-y: auto;
}

.panel h3 {
    font-size: 12px;
    font-weight: 600;
    color: var(--blue);
    margin-bottom: 6px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

/* P-Code disassembly panel (left) */
.panel-disasm {
    width: 280px;
    flex-shrink: 0;
    border-right: 1px solid var(--surface1);
    background: var(--mantle);
}

.disasm-init {
    font-size: 12px;
    color: var(--overlay1);
    font-style: italic;
    padding: 4px 0;
}

.disasm-view {
    font-size: 13px;
    line-height: 1.5;
}

.disasm-label {
    color: var(--mauve);
    font-weight: 600;
    padding: 2px 0 0 0;
}

.disasm-line {
    display: flex;
    gap: 6px;
    padding: 1px 4px;
    border-radius: 2px;
    white-space: nowrap;
}

.disasm-line.current {
    background: var(--surface0);
    font-weight: 600;
}

.disasm-marker {
    width: 12px;
    flex-shrink: 0;
    color: var(--yellow);
}

.disasm-addr {
    color: var(--overlay1);
    width: 40px;
    flex-shrink: 0;
}

.disasm-line.current .disasm-addr {
    color: var(--peach);
}

.disasm-opcode {
    color: var(--sapphire);
    width: 60px;
    flex-shrink: 0;
}

.disasm-line.current .disasm-opcode {
    color: var(--yellow);
}

.disasm-operand {
    color: var(--text);
}

.disasm-line.current .disasm-operand {
    color: var(--yellow);
}

.disasm-instr {
    color: var(--text);
}

.disasm-line.current .disasm-instr {
    color: var(--yellow);
}

/* Center column — stacked VM state + eval stack + output */
.panel-center {
    display: flex;
    flex-direction: column;
    flex: 1;
    min-width: 0;
    overflow: hidden;
}

/* VM State panel */
.panel-vm-state {
    flex-shrink: 0;
    border-bottom: 1px solid var(--surface1);
}

.state-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 13px;
}

.state-table td {
    padding: 2px 4px;
}

.state-name {
    color: var(--overlay2);
    width: 30px;
}

.state-val {
    color: var(--text);
    font-variant-numeric: tabular-nums;
    text-align: right;
}

.state-table tr.changed .state-val {
    color: var(--green);
    font-weight: 700;
}

.state-table tr.changed .state-name {
    color: var(--green);
}

.state-table tr.trap .state-val {
    color: var(--red);
    font-weight: 700;
}

.state-table tr.trap .state-name {
    color: var(--red);
}

/* Eval stack panel */
.panel-eval-stack {
    flex-shrink: 0;
    border-bottom: 1px solid var(--surface1);
    max-height: 200px;
    overflow-y: auto;
}

.stack-table tr.changed .stack-val,
.stack-table tr.changed .stack-dec {
    color: var(--green);
    font-weight: 700;
}

.stack-table tr.changed .stack-label {
    color: var(--green);
}

.stack-view {
    font-size: 13px;
