540→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
541→        match msg {
542→            Msg::Init => {
543→                self.load_binary();
544→                true
545→            }
546→            Msg::Tick => {
547→                if !self.running || self.halted {
548→                    return false;
549→                }
550→
551→                self.save_prev_state();
552→                let result = self.emulator.run_batch(BATCH_SIZE);
553→                self.instruction_count += result.instructions_run;
554→                self.collect_uart();
555→                self.check_halted(result.reason);
556→
557→                if self.running && !self.halted {
558→                    self.schedule_tick(ctx);
559→                }
560→                true
561→            }
562→            Msg::Reset => {
563→                self.running = false;
564→                self._tick_handle = None;
565→                self.load_binary();
566→                true
567→            }
568→            Msg::StepPcode => {
569→                if self.halted {
570→                    return false;
571→                }
572→                self.save_prev_state();
573→                let pstate = self.read_pcode_state();
574→
575→                if pstate.code_base == 0 {
576→                    // VM not yet initialized — run COR24 init until host PC
577→                    // reaches vm_loop (the top of the fetch-decode cycle).
578→                    for _ in 0..100_000u32 {
579→                        let result = self.emulator.step();
580→                        self.instruction_count += result.instructions_run;
581→                        self.collect_uart();
582→                        if matches!(result.reason, StopReason::Halted) {
583→                            self.halted = true;
584→                            self.running = false;
585→                            break;
586→                        }
587→                        if self.vm_loop_addr != 0
588→                            && self.emulator.snapshot().pc == self.vm_loop_addr
589→                        {
590→                            break;
591→                        }
592→                    }
593→                } else {
594→                    // Run COR24 until host PC returns to vm_loop with a
595→                    // different p-code PC, meaning one full p-code instruction
596→                    // has completed its fetch-decode-execute cycle.
597→                    // Run one full p-code fetch-decode-execute cycle:
598→                    // step COR24 instructions until host PC returns to
599→                    // vm_loop. Use do-while pattern (check after first step)
600→                    // because we may already be sitting on vm_loop.
601→                    let mut i = 0u32;
602→                    loop {
603→                        let result = self.emulator.step();
604→                        self.instruction_count += result.instructions_run;
605→                        self.collect_uart();
606→                        i += 1;
607→                        if matches!(result.reason, StopReason::Halted) {
608→                            self.halted = true;
609→                            self.running = false;
610→                            break;
611→                        }
612→                        if self.read_pcode_state().status != 0 {
613→                            break;
614→                        }
615→                        if i > 1 && self.emulator.snapshot().pc == self.vm_loop_addr {
616→                            break;
617→                        }
618→                        if i >= 50_000 {
619→                            break;
620→                        }
621→                    }
622→                }
623→                true
624→            }
625→            Msg::StepHost => {
626→                if self.halted {
627→                    return false;
628→                }
629→                self.save_prev_state();
630→                let result = self.emulator.step();
631→                self.instruction_count += result.instructions_run;
632→                self.collect_uart();
633→                self.check_halted(result.reason);
634→                true
635→            }
636→            Msg::PauseResume => {
637→                if self.halted {
638→                    return false;
639→                }
640→                self.running = !self.running;
641→                if self.running {
642→                    self.emulator.resume();
643→                    self.schedule_tick(ctx);
644→                } else {
645→                    self.emulator.pause();
646→                    self._tick_handle = None;
647→                }
648→                true
649→            }
650→            Msg::ToggleHost => {
651→                self.show_host = !self.show_host;
652→                true
653→            }
654→        }
655→    }
