.status {
    font-size: 13px;
    font-weight: 600;
    margin-left: 8px;
    color: var(--yellow);
}

.pc-display {
    font-size: 13px;
    color: var(--blue);
    margin-left: auto;
}

.host-pc {
    color: var(--overlay2);
    margin-left: 12px;
}

.instr-count {
    font-size: 12px;
    color: var(--overlay1);
    margin-left: 12px;
    font-variant-numeric: tabular-nums;
}

/* Memory region map bar */
.memory-map {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 4px 16px;
    border-bottom: 1px solid var(--surface1);
    flex-shrink: 0;
}

.memory-map-label {
    font-size: 11px;
    color: var(--overlay1);
    flex-shrink: 0;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.region-bar {
    display: flex;
    height: 16px;
    border-radius: 3px;
    overflow: hidden;
    font-size: 10px;
    flex: 1;
}

.region-bar .region {
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--crust);
    font-weight: 700;
    min-width: 2px;
    transition: width 0.3s;
}

.region-bar .region-code { background: var(--blue); }
.region-bar .region-estack { background: var(--green); }
.region-bar .region-cstack { background: var(--peach); }
.region-bar .region-globals { background: var(--mauve); }
.region-bar .region-heap { background: var(--yellow); }

/* Main panels — flexible columns */
.panels {
    display: flex;
    flex: 1;
    overflow: hidden;
    min-height: 0;
}

.panel {
    padding: 8px 12px;
    overflow-y: auto;
}

.panel h3 {
    font-size: 12px;
    font-weight: 600;
    color: var(--blue);
    margin-bottom: 6px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

/* P-Code disassembly panel (left) */
.panel-disasm {
    width: 280px;
    flex-shrink: 0;
    border-right: 1px solid var(--surface1);
    background: var(--mantle);
}

.disasm-init {
    font-size: 12px;
    color: var(--overlay1);
    font-style: italic;
    padding: 4px 0;
}

.disasm-view {
    font-size: 13px;
    line-height: 1.5;
}

.disasm-label {
    color: var(--mauve);
    font-weight: 600;
    padding: 2px 0 0 0;
}

.disasm-line {
    display: flex;
    gap: 6px;
    padding: 1px 4px;
    border-radius: 2px;
    white-space: nowrap;
}

.disasm-line.current {
    background: var(--surface0);
    font-weight: 600;
}

.disasm-marker {
    width: 12px;
    flex-shrink: 0;
    color: var(--yellow);
}

.disasm-addr {
    color: var(--overlay1);
    width: 40px;
    flex-shrink: 0;
}

.disasm-line.current .disasm-addr {
    color: var(--peach);
}

.disasm-opcode {
    color: var(--sapphire);
    width: 60px;
    flex-shrink: 0;
}

.disasm-line.current .disasm-opcode {
    color: var(--yellow);
}

.disasm-operand {
    color: var(--text);
}

.disasm-line.current .disasm-operand {
    color: var(--yellow);
}

.disasm-instr {
    color: var(--text);
}

.disasm-line.current .disasm-instr {
    color: var(--yellow);
}

/* Center column — stacked VM state + eval stack + output */
.panel-center {
    display: flex;
    flex-direction: column;
    flex: 1;
    min-width: 0;
    overflow: hidden;
}

/* VM State panel */
.panel-vm-state {
    flex-shrink: 0;
    border-bottom: 1px solid var(--surface1);
}

.state-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 13px;
}

.state-table td {
    padding: 2px 4px;
}

.state-name {
    color: var(--overlay2);
    width: 30px;
}

.state-val {
    color: var(--text);
    font-variant-numeric: tabular-nums;
    text-align: right;
}

.state-table tr.changed .state-val {
    color: var(--green);
    font-weight: 700;
}

.state-table tr.changed .state-name {
    color: var(--green);
}

.state-table tr.trap .state-val {
    color: var(--red);
    font-weight: 700;
}

.state-table tr.trap .state-name {
    color: var(--red);
}

/* Eval stack panel */
.panel-eval-stack {
    flex-shrink: 0;
    border-bottom: 1px solid var(--surface1);
    max-height: 200px;
    overflow-y: auto;
}

.stack-table tr.changed .stack-val,
.stack-table tr.changed .stack-dec {
    color: var(--green);
    font-weight: 700;
}

.stack-table tr.changed .stack-label {
    color: var(--green);
}

.stack-view {
    font-size: 13px;
}

.stack-view .empty {
    color: var(--overlay0);
    font-style: italic;
}

.stack-table {
    width: 100%;
    border-collapse: collapse;
}

.stack-table td {
    padding: 1px 4px;
}

.stack-label {
    color: var(--yellow);
    width: 30px;
    font-size: 11px;
    font-weight: 600;
}

.stack-val {
    color: var(--text);
    font-variant-numeric: tabular-nums;
    text-align: right;
    width: 60px;
}

.stack-dec {
    color: var(--overlay1);
    font-variant-numeric: tabular-nums;
    text-align: right;
    font-size: 12px;
}

/* Call frame panel */
.panel-call-frames {
    flex-shrink: 0;
    border-bottom: 1px solid var(--surface1);
    max-height: 180px;
    overflow-y: auto;
    padding: 8px 12px;
}

.panel-call-frames h3 {
    font-size: 12px;
    font-weight: 600;
    color: var(--blue);
    margin-bottom: 6px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.frames-view {
    font-size: 13px;
}

.frames-view .empty {
    color: var(--overlay0);
    font-style: italic;
}

.frame-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 12px;
}

.frame-table td {
    padding: 1px 4px;
    font-variant-numeric: tabular-nums;
}

.frame-header td {
    color: var(--overlay1);
    font-weight: 600;
    font-size: 11px;
    border-bottom: 1px solid var(--surface1);
    padding-bottom: 2px;
}

.frame-idx {
    color: var(--overlay1);
    width: 16px;
}

.frame-val {
    color: var(--text);
    text-align: right;
}

.frame-current .frame-val {
    color: var(--yellow);
    font-weight: 700;
}

.frame-current .frame-idx {
    color: var(--yellow);
}

/* Output panel */
.panel-output {
    flex: 1;
    min-height: 60px;
    overflow-y: auto;
}

.output-text {
    font-size: 13px;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-all;
    color: var(--subtext1);
    background: var(--crust);
    padding: 8px;
    border-radius: 4px;
    max-height: 100%;
    overflow-y: auto;
}

/* COR24 host drill-down panel (right, collapsible) */
.panel-host {
    width: 320px;
    flex-shrink: 0;
    border-left: 1px solid var(--surface1);
    background: var(--mantle);
    overflow-y: auto;
}

.panel-host h3 {
    color: var(--peach);
}

.host-regs {
    margin-bottom: 12px;
}

.host-disasm {
    font-size: 13px;
    line-height: 1.5;
    border-top: 1px solid var(--surface1);
    padding-top: 8px;
}

/* Register table (used in host panel) */
.reg-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 13px;
}

.reg-table td {
    padding: 2px 4px;
}

.reg-name {
    color: var(--overlay2);
    width: 30px;
}

.reg-val {
    color: var(--text);
    font-variant-numeric: tabular-nums;
    text-align: right;
}

.reg-table tr.changed .reg-val {
    color: var(--green);
    font-weight: 700;
}

.reg-table tr.changed .reg-name {
    color: var(--green);
}
